export const MarkerDemo = (): Html => {
  const h = html<never>()

  return h.div(
    [h.Class('flex w-full max-w-sm flex-col gap-8 py-12')],
    [
      marker([
        MarkerIcon({
          children: [branchIcon()],
        }),
        MarkerContent({
          children: ['Switched to a new branch'],
        }),
      ]),
      markerWithStatus([
        MarkerIcon({
          children: [Spinner()],
        }),
        MarkerContent({
          children: ['Thinking...'],
          className: 'shimmer',
        }),
      ]),
      Marker<never>({
        variant: 'separator',
        children: [
          MarkerContent({
            children: ['Conversation compacted'],
          }),
        ],
      }),
      marker([
        MarkerIcon({
          children: [searchIcon()],
        }),
        MarkerContent({
          children: ['Explored 4 files'],
        }),
      ]),
    ],
  )
}

